#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        char s[n + 1];
        scanf("%s", s);
        int count = 1;
        int operations = 0;
        for (int i = 1; i < n; i++) {
            if (s[i] == s[i - 1]) {
                count++;
                if (count > k) {
                    s[i] = (s[i] == '0') ? '1' : '0';
                    operations++;
                    count = 1;
                }
            } else {
                count = 1;
            }
        }
        printf("%d\n", operations);
        printf("%s\n", s);
    }
    return 0;
}

